import {
  html,
  customElement,
  unsafeHTML,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbModalBaseElement } from "@umbraco-cms/backoffice/modal";
import { FormService } from "@umbraco-forms/generated";
import { blobDownload } from "@umbraco-cms/backoffice/utils";
import type { FormsFormExportModalData } from "./index.js";

const elementName = "forms-form-export-modal";

@customElement(elementName)
export class FormsFormExportModalElement extends UmbModalBaseElement<FormsFormExportModalData> {
  async #export() {
    if (!this.data?.unique) throw new Error("unique is missing");
    const file = await FormService.getFormExport({ guid: this.data.unique });
    blobDownload(file, `form-${this.data.unique}.json`, "application/json");
    this._submitModal();
  }

  render() {
    return html`
      <umb-body-layout .headline=${this.localize.term("actions_export")}>
        <uui-box
          >${unsafeHTML(
            this.localize.term("formExport_exportInstruction")
          )}</uui-box
        >
        <uui-button
          slot="actions"
          label=${this.localize.term("general_cancel")}
          @click="${this._rejectModal}"
        ></uui-button>
        <uui-button
          slot="actions"
          label=${this.localize.term("actions_export")}
          look="primary"
          color="positive"
          @click=${this.#export}
        ></uui-button>
      </umb-body-layout>
    `;
  }
}

export default FormsFormExportModalElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFormExportModalElement;
  }
}
